unit lipdecide;

{$MODE FPC}

interface

uses
  globals;

function REALCOMPARE(A, B: real): COMPTYPE;
procedure DECIDE;

implementation

uses
  math;

{ REALCOMPARE - Compares two real numbers with six significant digits precision }
function REALCOMPARE(A, B: real): COMPTYPE;
const
  EPSILON = 1e-6;
var
  diff: real;
begin
  diff := abs(A - B);

  { Handle cases where one or both numbers are zero }
  if (abs(A) < EPSILON) and (abs(B) < EPSILON) then
    REALCOMPARE := EQ
  else if abs(A) < EPSILON then
    if B > 0 then
      REALCOMPARE := LT
    else
      REALCOMPARE := GT
  else if abs(B) < EPSILON then
    if A > 0 then
      REALCOMPARE := GT
    else
      REALCOMPARE := LT
  else
  begin
    { For non-zero numbers, compare with relative precision }
    if diff / max(abs(A), abs(B)) < EPSILON then
      REALCOMPARE := EQ
    else if A < B then
      REALCOMPARE := LT
    else
      REALCOMPARE := GT;
  end;
end;

{ Helper function to calculate distance between two points }
function Distance(x1, y1, x2, y2: real): real;
begin
  Distance := sqrt(sqr(x2 - x1) + sqr(y2 - y1));
end;

{ Helper function to calculate area of triangle formed by three points }
function TriangleArea(x1, y1, x2, y2, x3, y3: real): real;
begin
  TriangleArea := abs((x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)) / 2.0);
end;

{ Helper function to calculate angle at vertex point (x2,y2) formed by three points }
function AngleAtVertex(x1, y1, x2, y2, x3, y3: real): real;
var
  dot_product, mag1, mag2: real;
  cos_angle: real;
begin
  { Vector from vertex to first point }
  x1 := x1 - x2;
  y1 := y1 - y2;

  { Vector from vertex to third point }
  x3 := x3 - x2;
  y3 := y3 - y2;

  { Calculate magnitudes }
  mag1 := sqrt(x1 * x1 + y1 * y1);
  mag2 := sqrt(x3 * x3 + y3 * y3);

  { If either vector has zero length, angle is undefined }
  if (REALCOMPARE(mag1, 0) = EQ) or (REALCOMPARE(mag2, 0) = EQ) then
  begin
    AngleAtVertex := -1; { Return -1 to indicate undefined }
    exit;
  end;

  { Calculate dot product }
  dot_product := x1 * x3 + y1 * y3;

  { Calculate cosine of angle }
  cos_angle := dot_product / (mag1 * mag2);

  { Clamp to valid range for arccos }
  if cos_angle > 1.0 then
    cos_angle := 1.0
  else if cos_angle < -1.0 then
    cos_angle := -1.0;

  AngleAtVertex := arccos(cos_angle);
end;

{ Helper function to check if three points can be contained within a circle of given radius }
function CanBeContainedInCircle(x1, y1, x2, y2, x3, y3, radius: real): boolean;
var
  a, b, c, s, area, circumradius: real;
begin
  { Calculate side lengths }
  a := Distance(x2, y2, x3, y3);
  b := Distance(x1, y1, x3, y3);
  c := Distance(x1, y1, x2, y2);

  { Calculate area using triangle area helper }
  area := TriangleArea(x1, y1, x2, y2, x3, y3);

  { If area is zero (collinear points), use maximum distance }
  if REALCOMPARE(area, 0) = EQ then
  begin
    circumradius := max(max(a, b), c) / 2.0;
  end
  else
  begin
    { Calculate circumradius using formula: R = abc/(4*Area) }
    circumradius := (a * b * c) / (4.0 * area);
  end;

  CanBeContainedInCircle := REALCOMPARE(circumradius, radius) <> GT;
end;

{ Helper function to determine quadrant of a point }
function GetQuadrant(x, y: real): integer;
begin
  if (REALCOMPARE(x, 0) <> LT) and (REALCOMPARE(y, 0) <> LT) then
    GetQuadrant := 1  { Quadrant I }
  else if (REALCOMPARE(x, 0) = LT) and (REALCOMPARE(y, 0) <> LT) then
    GetQuadrant := 2  { Quadrant II }
  else if (REALCOMPARE(x, 0) = LT) and (REALCOMPARE(y, 0) = LT) then
    GetQuadrant := 3  { Quadrant III }
  else
    GetQuadrant := 4; { Quadrant IV }
end;

{ Helper function to calculate distance from point to line }
function DistancePointToLine(px, py, x1, y1, x2, y2: real): real;
var
  A, B, C, distance: real;
begin
  { If endpoints are the same, return distance to that point }
  if (REALCOMPARE(x1, x2) = EQ) and (REALCOMPARE(y1, y2) = EQ) then
  begin
    DistancePointToLine := Distance(px, py, x1, y1);
    exit;
  end;

  { Line equation: Ax + By + C = 0 }
  A := y2 - y1;
  B := x1 - x2;
  C := x2 * y1 - x1 * y2;

  { Distance formula: |Ax + By + C| / sqrt(A² + B²) }
  distance := abs(A * px + B * py + C) / sqrt(A * A + B * B);
  DistancePointToLine := distance;
end;

{ Main DECIDE procedure }
procedure DECIDE;
var
  i, j, k: integer;
  quadrants_used: array[1..4] of boolean;
  quad_count: integer;
  angle: real;
  area: real;
  dist: real;
  all_true: boolean;
begin
  { Initialize CMV array }
  for i := 1 to 15 do
    CMV[i] := false;

  { LIC 1: Distance between consecutive points > LENGTH1 }
  for i := 1 to NUMPOINTS - 1 do
  begin
    if REALCOMPARE(Distance(X[i], Y[i], X[i+1], Y[i+1]), PARAMETERS.LENGTH1) = GT then
    begin
      CMV[1] := true;
      break;
    end;
  end;

  { LIC 2: Three consecutive points cannot be contained in circle of radius RADIUS1 }
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - 2 do
    begin
      if not CanBeContainedInCircle(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2], PARAMETERS.RADIUS1) then
      begin
        CMV[2] := true;
        break;
      end;
    end;
  end;

  { LIC 3: Angle condition }
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - 2 do
    begin
      angle := AngleAtVertex(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2]);
      if angle >= 0 then { Valid angle }
      begin
        if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or
           (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
        begin
          CMV[3] := true;
          break;
        end;
      end;
    end;
  end;

  { LIC 4: Triangle area > AREA1 }
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - 2 do
    begin
      area := TriangleArea(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2]);
      if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
      begin
        CMV[4] := true;
        break;
      end;
    end;
  end;

  { LIC 5: Q_PTS consecutive points in more than QUADS quadrants }
  if NUMPOINTS >= PARAMETERS.Q_PTS then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
    begin
      { Initialize quadrant tracking }
      for j := 1 to 4 do
        quadrants_used[j] := false;

      { Check quadrants for Q_PTS consecutive points }
      for j := i to i + PARAMETERS.Q_PTS - 1 do
      begin
        quadrants_used[GetQuadrant(X[j], Y[j])] := true;
      end;

      { Count used quadrants }
      quad_count := 0;
      for j := 1 to 4 do
        if quadrants_used[j] then
          inc(quad_count);

      if quad_count > PARAMETERS.QUADS then
      begin
        CMV[5] := true;
        break;
      end;
    end;
  end;

  { LIC 6: Consecutive points with X[j] - X[i] < 0 }
  for i := 1 to NUMPOINTS - 1 do
  begin
    if REALCOMPARE(X[i+1] - X[i], 0) = LT then
    begin
      CMV[6] := true;
      break;
    end;
  end;

  { LIC 7: Distance from line condition }
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
    begin
      for j := i + 1 to i + PARAMETERS.N_PTS - 2 do
      begin
        dist := DistancePointToLine(X[j], Y[j], X[i], Y[i], X[i + PARAMETERS.N_PTS - 1], Y[i + PARAMETERS.N_PTS - 1]);
        if REALCOMPARE(dist, PARAMETERS.DIST) = GT then
        begin
          CMV[7] := true;
          break;
        end;
      end;
      if CMV[7] then break;
    end;
  end;

  { LIC 8: Two points separated by K_PTS with distance > LENGTH1 }
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
    begin
      j := i + PARAMETERS.K_PTS + 1;
      if REALCOMPARE(Distance(X[i], Y[i], X[j], Y[j]), PARAMETERS.LENGTH1) = GT then
      begin
        CMV[8] := true;
        break;
      end;
    end;
  end;

  { LIC 9: Three points separated by A_PTS and B_PTS, cannot be contained in circle }
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
    begin
      j := i + PARAMETERS.A_PTS + 1;
      k := j + PARAMETERS.B_PTS + 1;
      if not CanBeContainedInCircle(X[i], Y[i], X[j], Y[j], X[k], Y[k], PARAMETERS.RADIUS1) then
      begin
        CMV[9] := true;
        break;
      end;
    end;
  end;

  { LIC 10: Angle condition with separated points }
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
    begin
      j := i + PARAMETERS.C_PTS + 1;
      k := j + PARAMETERS.D_PTS + 1;
      angle := AngleAtVertex(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
      if angle >= 0 then { Valid angle }
      begin
        if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or
           (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
        begin
          CMV[10] := true;
          break;
        end;
      end;
    end;
  end;

  { LIC 11: Triangle area condition with separated points }
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
    begin
      j := i + PARAMETERS.E_PTS + 1;
      k := j + PARAMETERS.F_PTS + 1;
      area := TriangleArea(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
      if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
      begin
        CMV[11] := true;
        break;
      end;
    end;
  end;

  { LIC 12: Two points separated by G_PTS with X[j] - X[i] < 0 }
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
    begin
      j := i + PARAMETERS.G_PTS + 1;
      if REALCOMPARE(X[j] - X[i], 0) = LT then
      begin
        CMV[12] := true;
        break;
      end;
    end;
  end;

  { LIC 13: Both distance conditions with K_PTS separation }
  if NUMPOINTS >= 3 then
  begin
    { Check for distance > LENGTH1 }
    for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
    begin
      j := i + PARAMETERS.K_PTS + 1;
      if REALCOMPARE(Distance(X[i], Y[i], X[j], Y[j]), PARAMETERS.LENGTH1) = GT then
      begin
        { Found first condition, now check for second condition }
        for k := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
        begin
          j := k + PARAMETERS.K_PTS + 1;
          if REALCOMPARE(Distance(X[k], Y[k], X[j], Y[j]), PARAMETERS.LENGTH2) = LT then
          begin
            CMV[13] := true;
            break;
          end;
        end;
        break;
      end;
    end;
  end;

  { LIC 14: Both circle conditions with A_PTS and B_PTS separation }
  if NUMPOINTS >= 5 then
  begin
    { Check for cannot be contained in RADIUS1 }
    for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
    begin
      j := i + PARAMETERS.A_PTS + 1;
      k := j + PARAMETERS.B_PTS + 1;
      if not CanBeContainedInCircle(X[i], Y[i], X[j], Y[j], X[k], Y[k], PARAMETERS.RADIUS1) then
      begin
        { Found first condition, now check for second condition }
        for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
        begin
          j := i + PARAMETERS.A_PTS + 1;
          k := j + PARAMETERS.B_PTS + 1;
          if CanBeContainedInCircle(X[i], Y[i], X[j], Y[j], X[k], Y[k], PARAMETERS.RADIUS2) then
          begin
            CMV[14] := true;
            break;
          end;
        end;
        break;
      end;
    end;
  end;

  { LIC 15: Both area conditions with E_PTS and F_PTS separation }
  if NUMPOINTS >= 5 then
  begin
    { Check for area > AREA1 }
    for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
    begin
      j := i + PARAMETERS.E_PTS + 1;
      k := j + PARAMETERS.F_PTS + 1;
      area := TriangleArea(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
      if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
      begin
        { Found first condition, now check for second condition }
        for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
        begin
          j := i + PARAMETERS.E_PTS + 1;
          k := j + PARAMETERS.F_PTS + 1;
          area := TriangleArea(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
          if REALCOMPARE(area, PARAMETERS.AREA2) = LT then
          begin
            CMV[15] := true;
            break;
          end;
        end;
        break;
      end;
    end;
  end;

  { Calculate PUM from CMV and LCM }
  for i := 1 to 15 do
  begin
    for j := 1 to 15 do
    begin
      if i <> j then { Off-diagonal elements }
      begin
        case LCM[i, j] of
          NOTUSED: PUM[i, j] := true;
          ANDD:    PUM[i, j] := CMV[i] and CMV[j];
          ORR:     PUM[i, j] := CMV[i] or CMV[j];
        end;
      end;
      { Diagonal elements are input values, don't modify them }
    end;
  end;

  { Calculate FUV from PUM }
  for i := 1 to 15 do
  begin
    if not PUM[i, i] then
      FUV[i] := true { LIC should not hold back launch }
    else
    begin
      { Check if all elements in row i are true }
      all_true := true;
      for j := 1 to 15 do
      begin
        if not PUM[i, j] then
        begin
          all_true := false;
          break;
        end;
      end;
      FUV[i] := all_true;
    end;
  end;

  { Final launch decision }
  LAUNCH := true;
  for i := 1 to 15 do
  begin
    if not FUV[i] then
    begin
      LAUNCH := false;
      break;
    end;
  end;
end;

end.
